const book: BibleBook = {
  id: 'hosea',
  name: 'Oseias',
  englishName: 'Hosea',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'Yahweh’s word that came to Hosea the son of Beeri, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah, and in the days of Jeroboam the son of Joash, king of Israel.', pt: 'A palavra do Senhor, que veio a Oséias, filho de Beeri, nos dias de Uzias, Jotão, Acaz e Ezequias, reis de Judá, e nos dias de Jeroboão, filho de Joás, rei de Israel.' },
      { v: 2, en: 'When Yahweh spoke at first by Hosea, Yahweh said to Hosea, “Go, take for yourself a wife of prostitution and children of unfaithfulness; for the land commits great adultery, forsaking Yahweh.”', pt: 'Quando o Senhor falou no princípio por Oséias, disse o Senhor a Oséias: Vai, toma por esposa uma mulher de prostituições, e filhos de prostituição; porque a terra se prostituiu, apartando-se do Senhor.' },
      { v: 3, en: 'So he went and took Gomer the daughter of Diblaim; and she conceived, and bore him a son.', pt: 'Ele se foi, pois, e tomou a Gomer, filha de Diblaim; e ela concebeu, e lhe deu um filho.' },
      { v: 4, en: 'Yahweh said to him, “Call his name Jezreel; for yet a little while, and I will avenge the blood of Jezreel on the house of Jehu, and will cause the kingdom of the house of Israel to cease.', pt: 'E disse-lhe o Senhor: Põe-lhe o nome de Jizreel; porque daqui a pouco visitarei o sangue de Jizreel sobre a casa de Jeú, e farei cessar o reino da casa de Israel.' },
      { v: 5, en: 'It will happen in that day that I will break the bow of Israel in the valley of Jezreel.”', pt: 'E naquele dia quebrarei o arco de Israel no vale de Jizreel.' },
      { v: 6, en: 'She conceived again, and bore a daughter. Then he said to him, “Call her name Lo-Ruhamah ; for I will no longer have mercy on the house of Israel, that I should in any way pardon them.', pt: 'E tornou ela a conceber, e deu à luz uma filha. E o Senhor disse a Oséias: Põe-lhe o nome de Lo-Ruama; porque não tornarei mais a compadecer-me da casa de Israel, nem a perdoar-lhe de maneira alguma.' },
      { v: 7, en: 'But I will have mercy on the house of Judah, and will save them by Yahweh their God, and will not save them by bow, sword, battle, horses, or horsemen.”', pt: 'Mas da casa se Judá me compadecerei, e os salvarei pelo Senhor seu Deus, pois não os salvarei pelo arco, nem pela espada, nem pela guerra, nem pelos cavalos, nem pelos cavaleiros.' },
      { v: 8, en: 'Now when she had weaned Lo-Ruhamah, she conceived, and bore a son.', pt: 'Ora depois de haver desmamado a Lo-Ruama, concebeu e deu à luz um filho.' },
      { v: 9, en: 'He said, “Call his name Lo-Ammi ; for you are not my people, and I will not be yours.', pt: 'E o Senhor disse: Põe-lhe o nome de Lo-Ami; porque vós não sois meu povo, nem sou eu vosso Deus.' },
      { v: 10, en: 'Yet the number of the children of Israel will be as the sand of the sea, which can’t be measured or counted; and it will come to pass that, in the place where it was said to them, ‘You are not my people,’ they will be called ‘sons of the living God.’', pt: 'Todavia o número dos filhos de Israel será como a areia do mar, que não pode ser medida nem contada; e no lugar onde se lhes dizia: Vós não sois meu povo, se lhes dirá: Vós sois os filhos do Deus vivo.' },
      { v: 11, en: 'The children of Judah and the children of Israel will be gathered together, and they will appoint themselves one head, and will go up from the land; for great will be the day of Jezreel.', pt: 'E os filhos de Judá e os filhos de Israel juntos se congregarão, e constituirão sobre si uma só cabeça, e subirão da terra; pois grande será o dia de Jizreel.' },
    ],
    2: [
      { v: 1, en: '“Say to your brothers, ‘My people!’ and to your sisters, ‘My loved one!’', pt: 'Dizei a vossos irmãos: Ami; e a vossas irmãs: Ruama.' },
      { v: 2, en: 'Contend with your mother! Contend, for she is not my wife, neither am I her husband; and let her put away her prostitution from her face, and her adulteries from between her breasts;', pt: 'Contendei com vossa mãe, contendei; porque ela não é minha mulher, e eu não sou seu marido; para que ela afaste as suas prostituições da sua face e os seus adultérios de entre os seus seios;' },
      { v: 3, en: 'Lest I strip her naked, and make her bare as in the day that she was born, and make her like a wilderness, and set her like a dry land, and kill her with thirst.', pt: 'para que eu não a deixe despida, e a ponha como no dia em que nasceu, e a faça como um deserto, e a torne como uma terra seca, e a mate à sede.' },
      { v: 4, en: 'Indeed, on her children I will have no mercy; for they are children of unfaithfulness;', pt: 'Até de seus filhos não me compadecerei; porquanto são filhos de prostituições.' },
      { v: 5, en: 'For their mother has played the prostitute. She who conceived them has done shamefully; for she said, ‘I will go after my lovers, who give me my bread and my water, my wool and my flax, my oil and my drink.’', pt: 'porque sua mãe se prostituiu; aquela que os concebeu houve- se torpemente; porque diz: Irei após os meus amantes, que me dão o meu pão e a minha água, a minha lã e o meu linho, o meu óleo e as minhas bebidas.' },
      { v: 6, en: 'Therefore behold, I will hedge up your way with thorns, and I will build a wall against her, that she can’t find her way.', pt: 'Portanto, eis que lhe cercarei o caminho com espinhos, e contra ela levantarei uma sebe, para que ela não ache as suas veredas.' },
      { v: 7, en: 'She will follow after her lovers, but she won’t overtake them; and she will seek them, but won’t find them. Then she will say, ‘I will go and return to my first husband; for then was it better with me than now.’', pt: 'Ela irá em seguimento de seus amantes, mas não os alcançará; buscá-los-á, mas não os achará; então dirá: Irei, e voltarei a meu primeiro marido, porque melhor me ia então do que agora.' },
      { v: 8, en: 'For she did not know that I gave her the grain, the new wine, and the oil, and multiplied to her silver and gold, which they used for Baal.', pt: 'Ora, ela não reconhece que fui eu o que lhe dei o grão, e o vinho, e o azeite, e que lhe multipliquei a prata e o ouro, que eles usaram para Baal.' },
      { v: 9, en: 'Therefore I will take back my grain in its time, and my new wine in its season, and will pluck away my wool and my flax which should have covered her nakedness.', pt: 'Portanto, tornarei a tirar o meu grão a seu tempo e o meu vinho no seu tempo determinado; e arrebatarei a minha lã e o meu linho, com que cobriam a sua nudez.' },
      { v: 10, en: 'Now I will uncover her lewdness in the sight of her lovers, and no one will deliver her out of my hand.', pt: 'E agora descobrirei a sua vileza diante dos olhos dos seus amantes, e ninguém a livrará da minha mão.' },
      { v: 11, en: 'I will also cause all her celebrations to cease: her feasts, her new moons, her Sabbaths, and all her solemn assemblies.', pt: 'Também farei cessar todo o seu gozo, as suas festas, as suas luas novas, e os seus sábados, e todas as suas assembléias solenes.' },
      { v: 12, en: 'I will lay waste her vines and her fig trees, about which she has said, ‘These are my wages that my lovers have given me; and I will make them a forest,’ and the animals of the field shall eat them.', pt: 'E devastarei a sua vide e a sua figueira, de que ela diz: É esta a paga que me deram os meus amantes; eu, pois, farei delas um bosque, e as feras do campo as devorarão.' },
      { v: 13, en: 'I will visit on her the days of the Baals, to which she burned incense, when she decked herself with her earrings and her jewels, and went after her lovers, and forgot me,” says Yahweh.', pt: 'Castigá-la-ei pelos dias dos baalins, nos quais elas lhes queimava incenso, e se adornava com as suas arrecadas e as suas jóias, e, indo atrás dos seus amantes, se esquecia de mim, diz o Senhor.' },
      { v: 14, en: '“Therefore behold, I will allure her, and bring her into the wilderness, and speak tenderly to her.', pt: 'Portanto, eis que eu a atrairei, e a levarei para o deserto, e lhe falarei ao coração.' },
      { v: 15, en: 'I will give her vineyards from there, and the valley of Achor for a door of hope; and she will respond there, as in the days of her youth, and as in the day when she came up out of the land of Egypt.', pt: 'E lhe darei as suas vinhas dali, e o vale de Acor por porta de esperança; e ali responderá, como nos dias da sua mocidade, e como no dia em que subiu da terra do Egito.' },
      { v: 16, en: 'It will be in that day,” says Yahweh, “that you will call me ‘my husband,’ and no longer call me ‘my master.’', pt: 'E naquele dia, diz o Senhor, ela me chamará meu marido; e não me chamará mais meu Baal.' },
      { v: 17, en: 'For I will take away the names of the Baals out of her mouth, and they will no longer be mentioned by name.', pt: 'Pois da sua boca tirarei os nomes dos baalins, e não mais se fará menção desses nomes.' },
      { v: 18, en: 'In that day I will make a covenant for them with the animals of the field, and with the birds of the sky, and with the creeping things of the ground. I will break the bow, the sword, and the battle out of the land, and will make them lie down safely.', pt: 'Naquele dia farei por eles aliança com as feras do campo, e com as aves do céu, e com os répteis da terra; e da terra tirarei o arco, e a espada, e a guerra, e os farei deitar em segurança.' },
      { v: 19, en: 'I will betroth you to me forever. Yes, I will betroth you to me in righteousness, in justice, in loving kindness, and in compassion.', pt: 'E desposar-te-ei comigo para sempre; sim, desposar-te-ei comigo em justiça, e em juízo, e em amorável benignidade, e em misericórdias;' },
      { v: 20, en: 'I will even betroth you to me in faithfulness; and you shall know Yahweh.', pt: 'e desposar-te-ei comigo em fidelidade, e conhecerás ao Senhor.' },
      { v: 21, en: 'It will happen in that day, I will respond,” says Yahweh, “I will respond to the heavens, and they will respond to the earth;', pt: 'Naquele dia responderei, diz o Senhor; responderei aos céus, e estes responderão a terra;' },
      { v: 22, en: 'and the earth will respond to the grain, and the new wine, and the oil; and they will respond to Jezreel.', pt: 'a terra responderá ao trigo, e ao vinho, e ao azeite, e estes responderão a Jizreel.' },
      { v: 23, en: 'I will sow her to me in the earth; and I will have mercy on her who had not obtained mercy; and I will tell those who were not my people, ‘You are my people;’ and they will say, ‘My God!’”', pt: 'E semeá-lo-ei para mim na terra, e compadecer-me-ei de Lo-Ruama; e a e Lo-Ami direi: Tu és meu povo; e ele dirá: Tu és o meu Deus.' },
    ],
    3: [
      { v: 1, en: 'Yahweh said to me, “Go again, love a woman loved by another, and an adulteress, even as Yahweh loves the children of Israel, though they turn to other gods, and love cakes of raisins.”', pt: 'Disse-me o Senhor: Vai outra vez, ama uma mulher, amada de seu amigo, e adúltera, como o Senhor ama os filhos de Israel, embora eles se desviem para outros deuses, e amem passas de uvas.' },
      { v: 2, en: 'So I bought her for myself for fifteen pieces of silver and a homer and a half of barley.', pt: 'Assim eu comprei para mim tal mulher por quinze peças de prata, e um hômer e meio de cevada;' },
      { v: 3, en: 'I said to her, “You shall stay with me many days. You shall not play the prostitute, and you shall not be with any other man. I will also be so toward you.”', pt: 'e lhe disse: Por muitos dias tu ficarás esperando por mim; não te prostituirás, nem serás mulher de outro homem; assim também eu esperarei por ti.' },
      { v: 4, en: 'For the children of Israel shall live many days without king, and without prince, and without sacrifice, and without sacred stone, and without ephod or idols.', pt: 'Pois os filhos de Israel ficarão por muitos dias sem rei, sem príncipe, sem sacrifício, sem coluna, e sem éfode ou terafins.' },
      { v: 5, en: 'Afterward the children of Israel shall return, and seek Yahweh their God, and David their king, and shall come with trembling to Yahweh and to his blessings in the last days.', pt: 'Depois tornarão os filhos de Israel, e buscarão ao Senhor, seu Deus, e a Davi, seu rei; e com temor chegarão nos últimos dias ao Senhor, e à sua bondade.' },
    ],
    4: [
      { v: 1, en: 'Hear Yahweh’s word, you children of Israel; for Yahweh has a charge against the inhabitants of the land: “Indeed there is no truth, nor goodness, nor knowledge of God in the land.', pt: 'Ouvi a palavra do Senhor, vós, filhos de Israel; pois o Senhor tem uma contenda com os habitantes da terra; porque na terra não há verdade, nem benignidade, nem conhecimento de Deus.' },
      { v: 2, en: 'There is cursing, lying, murder, stealing, and committing adultery; they break boundaries, and bloodshed causes bloodshed.', pt: 'Só prevalecem o perjurar, o mentir, o matar, o furtar, e o adulterar; há violências e homicídios sobre homicídios.' },
      { v: 3, en: 'Therefore the land will mourn, and everyone who dwells therein will waste away. all living things in her, even the animals of the field and the birds of the sky; yes, the fish of the sea also die.', pt: 'Por isso a terra se lamenta, e todo o que nela mora desfalece, juntamente com os animais do campo e com as aves do céu; e até os peixes do mar perecem.' },
      { v: 4, en: '“Yet let no man bring a charge, neither let any man accuse; For your people are like those who bring charges against a priest.', pt: 'Todavia ninguém contenda, ninguém repreenda; pois é contigo a minha contenda, ó sacerdote.' },
      { v: 5, en: 'You will stumble in the day, and the prophet will also stumble with you in the night; and I will destroy your mother.', pt: 'Por isso tu tropeçarás de dia, e o profeta contigo tropeçará de noite; e destruirei a tua mãe.' },
      { v: 6, en: 'My people are destroyed for lack of knowledge. Because you have rejected knowledge, I will also reject you, that you may be no priest to me. Because you have forgotten your God’s law, I will also forget your children.', pt: 'O meu povo está sendo destruído, porque lhe falta o conhecimento. Porquanto rejeitaste o conhecimento, também eu te rejeitarei, para que não sejas sacerdote diante de mim; visto que te esqueceste da lei do teu Deus, também eu me esquecerei de teus filhos.' },
      { v: 7, en: 'As they were multiplied, so they sinned against me. I will change their glory into shame.', pt: 'Quanto mais eles se multiplicaram tanto mais contra mim pecaram: eu mudarei a sua honra em vergonha.' },
      { v: 8, en: 'They feed on the sin of my people, and set their heart on their iniquity.', pt: 'Alimentavam-se do pecado do meu povo, e de coração desejam a iniqüidade dele.' },
      { v: 9, en: 'It will be, like people, like priest; and I will punish them for their ways, and will repay them for their deeds.', pt: 'Por isso, como é o povo, assim será o sacerdote; e castigá-lo-ei conforme os seus caminhos, e lhe darei a recompensa das suas obras.' },
      { v: 10, en: 'They will eat, and not have enough. They will play the prostitute, and will not increase; because they have abandoned giving to Yahweh.', pt: 'Comerão, mas não se fartarão; entregar-se-ão à luxúria, mas não se multiplicarão; porque deixaram de atentar para o Senhor.' },
      { v: 11, en: 'Prostitution, wine, and new wine take away understanding.', pt: 'A incontinência, e o vinho, e o mosto tiram o entendimento.' },
      { v: 12, en: 'My people consult with their wooden idol, and answer to a stick of wood. Indeed the spirit of prostitution has led them astray, and they have been unfaithful to their God.', pt: 'O meu povo consulta ao seu pau, e a sua vara lhe dá respostas, porque o espírito de luxúria os enganou, e eles, prostituindo-se, abandonam o seu Deus.' },
      { v: 13, en: 'They sacrifice on the tops of the mountains, and burn incense on the hills, under oaks and poplars and terebinths, because its shade is good. Therefore your daughters play the prostitute, and your brides commit adultery.', pt: 'Sacrificam sobre os cumes dos montes; e queimam incenso sobre os outeiros, debaixo do carvalho, do álamo, e do terebinto, porque é boa a sua sombra; por isso vossas filhas se prostituem, e as vossas noras adulteram.' },
      { v: 14, en: 'I will not punish your daughters when they play the prostitute, nor your brides when they commit adultery; because the men consort with prostitutes, and they sacrifice with the shrine prostitutes; so the people without understanding will come to ruin.', pt: 'Eu não castigarei vossas filhas, quando se prostituem, nem vossas noras, quando adulteram; porque os homens mesmos com as prostitutas se desviam, e com as meretrizes sacrificam; pois o povo que não tem entendimento será transtornado.' },
      { v: 15, en: '“Though you, Israel, play the prostitute, yet don’t let Judah offend; and don’t come to Gilgal, neither go up to Beth Aven, nor swear, ‘As Yahweh lives.’', pt: 'Ainda que tu, ó Israel, te queiras prostituir contudo não se faça culpado Judá; não venhais a Gilgal, e não subais a Bete-Ávem nem jureis, dizendo: Vive o Senhor.' },
      { v: 16, en: 'For Israel has behaved extremely stubbornly, like a stubborn heifer. Then how will Yahweh feed them like a lamb in a meadow.', pt: 'Porque como novilha obstinada se rebelou Israel; agora o Senhor os apascentará como a um cordeiro num lugar espaçoso.' },
      { v: 17, en: 'Ephraim is joined to idols. Leave him alone!', pt: 'Efraim está entregue aos ídolos; deixa-o.' },
      { v: 18, en: 'Their drink has become sour. They play the prostitute continually. Her rulers dearly love their shameful way.', pt: 'Acabando eles de beber, lançam-se à luxúria; certamente os seus príncipes amam a vergonha.' },
      { v: 19, en: 'The wind has wrapped her up in its wings; and they shall be disappointed because of their sacrifices.', pt: 'Um vento os envolveu nas suas asas; e eles se envergonharão por causa dos seus sacrifícios.' },
    ],
    5: [
      { v: 1, en: '“Listen to this, you priests! Listen, house of Israel, and give ear, house of the king! For the judgment is against you; for you have been a snare at Mizpah, and a net spread on Tabor.', pt: 'Ouvi isto, ó sacerdotes, e escutai, ó casa de Israel, e dai ouvidos, ó casa do rei; porque contra vós se dirige este juízo; pois que vos tornastes um laço para Mizpá, e uma rede estendida sobre o Tabor.' },
      { v: 2, en: 'The rebels are deep in slaughter; but I discipline all of them.', pt: 'Os revoltosos se aprofundaram na corrupção; mas eu os castigarei a todos eles.' },
      { v: 3, en: 'I know Ephraim, and Israel is not hidden from me; for now, Ephraim, you have played the prostitute. Israel is defiled.', pt: 'Eu conheço a Efraim, e Israel não se me esconde; porque agora te tens prostituído, ó Efraim, e Israel se contaminou.' },
      { v: 4, en: 'Their deeds won’t allow them to turn to their God; for the spirit of prostitution is within them, and they don’t know Yahweh.', pt: 'As suas ações não lhes permitem voltar para o seu Deus; porque o espírito da prostituição está no meio deles, e não conhecem ao Senhor.' },
      { v: 5, en: 'The pride of Israel testifies to his face. Therefore Israel and Ephraim will stumble in their iniquity. Judah also will stumble with them.', pt: 'A soberba de Israel testifica contra eles; e Israel e Efraim cairão pela sua iniqüidade, e Judá cairá juntamente com eles.' },
      { v: 6, en: 'They will go with their flocks and with their herds to seek Yahweh; but they won’t find him. He has withdrawn himself from them.', pt: 'Eles irão com os seus rebanhos e com as suas manadas, para buscarem ao Senhor, mas não o acharão; ele se retirou deles.' },
      { v: 7, en: 'They are unfaithful to Yahweh; for they have borne illegitimate children. Now the new moon will devour them with their fields.', pt: 'Aleivosamente se houveram contra o Senhor, porque geraram filhos estranhos; agora a festa da lua nova os consumirá, juntamente com as suas porções.' },
      { v: 8, en: '“Blow the cornet in Gibeah, and the trumpet in Ramah! Sound a battle cry at Beth Aven, behind you, Benjamin!', pt: 'Tocai a corneta em Gibeá, a trombeta em Ramá; soltai o alarma em Bete-Áven; após ti, ó Benjamim.' },
      { v: 9, en: 'Ephraim will become a desolation in the day of rebuke. Among the tribes of Israel, I have made known that which will surely be.', pt: 'Efraim será para assolação no dia do castigo: entre as tribos de Israel declaro o que é certo.' },
      { v: 10, en: 'The princes of Judah are like those who remove a landmark. I will pour out my wrath on them like water.', pt: 'Os príncipes de Judá são como os que removem os marcos; derramarei, pois, o meu furor sobre eles como água.' },
      { v: 11, en: 'Ephraim is oppressed, he is crushed in judgment; Because he is intent in his pursuit of idols.', pt: 'Efraim está oprimido e quebrantado no juízo, porque foi do seu agrado andar após a vaidade.' },
      { v: 12, en: 'Therefore I am to Ephraim like a moth, and to the house of Judah like rottenness.', pt: 'Portanto para Efraim serei como a traça e para a casa de Judá como a podridão.' },
      { v: 13, en: '“When Ephraim saw his sickness, and Judah his wound, Then Ephraim went to Assyria, and sent to king Jareb: but he is not able to heal you, neither will he cure you of your wound.', pt: 'Quando Efraim viu a sua enfermidade, e Judá a sua chaga, recorreu Efraim à Assíria e enviou ao rei Jarebe; mas ele não pode curar-vos, nem sarar a vossa chaga.' },
      { v: 14, en: 'For I will be to Ephraim like a lion, and like a young lion to the house of Judah. I myself will tear in pieces and go away. I will carry off, and there will be no one to deliver.', pt: 'Pois para Efraim serei como um leão, e como um leão novo para a casa de Judá; eu, sim eu despedaçarei, e ir-me-ei embora; arrebatarei, e não haverá quem livre.' },
      { v: 15, en: 'I will go and return to my place, until they acknowledge their offense, and seek my face. In their affliction they will seek me earnestly.”', pt: 'Irei, e voltarei para o meu lugar, até que se reconheçam culpados e busquem a minha face; estando eles aflitos, ansiosamente me buscarão.' },
    ],
    6: [
      { v: 1, en: '“Come, and let us return to Yahweh; for he has torn us to pieces, and he will heal us; he has injured us, and he will bind up our wounds.', pt: 'Vinde, e tornemos para o Senhor, porque ele despedaçou e nos sarará; fez a ferida, e no-la atará.' },
      { v: 2, en: 'After two days he will revive us. On the third day he will raise us up, and we will live before him.', pt: 'Depois de dois dias nos ressuscitará: ao terceiro dia nos levantará, e viveremos diante dele.' },
      { v: 3, en: 'Let us acknowledge Yahweh. Let us press on to know Yahweh. As surely as the sun rises, Yahweh will appear. He will come to us like the rain, like the spring rain that waters the earth.”', pt: 'Conheçamos, e prossigamos em conhecer ao Senhor; a sua saída, como a alva, é certa; e ele a nós virá como a chuva, como a chuva serôdia que rega a terra.' },
      { v: 4, en: '“Ephraim, what shall I do to you? Judah, what shall I do to you? For your love is like a morning cloud, and like the dew that disappears early.', pt: 'Que te farei, ó Efraim? que te farei, ó Judá? porque o vosso amor é como a nuvem da manhã, e como o orvalho que cedo passa.' },
      { v: 5, en: 'Therefore I have cut them to pieces with the prophets; I killed them with the words of my mouth. Your judgments are like a flash of lightning.', pt: 'Por isso os abati pelos profetas; pela palavra da minha boca os matei; e os meus juízos a teu respeito sairão como a luz.' },
      { v: 6, en: 'For I desire mercy, and not sacrifice; and the knowledge of God more than burnt offerings.', pt: 'Pois misericórdia quero, e não sacrifícios; e o conhecimento de Deus, mais do que os holocaustos.' },
      { v: 7, en: 'But they, like Adam, have broken the covenant. They were unfaithful to me, there.', pt: 'Eles, porém, como Adão, transgrediram o pacto; nisso eles se portaram aleivosamente contra mim.' },
      { v: 8, en: 'Gilead is a city of those who work iniquity; it is stained with blood.', pt: 'Gileade é cidade de malfeitores, está manchada de sangue.' },
      { v: 9, en: 'As gangs of robbers wait to ambush a man, so the company of priests murder on the path toward Shechem, committing shameful crimes.', pt: 'Como hordas de salteadores que espreitam alguém, assim é a companhia dos sacerdotes que matam no caminho para Siquém; sim, cometem a vilania.' },
      { v: 10, en: 'In the house of Israel I have seen a horrible thing. There is prostitution in Ephraim. Israel is defiled.', pt: 'Vejo uma coisa horrenda na casa de Israel; ali está a prostituição de Efraim; Israel está contaminado.' },
      { v: 11, en: '“Also, Judah, there is a harvest appointed for you, when I restore the fortunes of my people.', pt: 'Também para ti, ó Judá, está determinada uma ceifa. Ao querer eu trazer do cativeiro o meu povo,' },
    ],
    7: [
      { v: 1, en: 'When I would heal Israel, then the iniquity of Ephraim is uncovered, also the wickedness of Samaria; for they commit falsehood, and the thief enters in, and the gang of robbers ravages outside.', pt: 'ao querer eu sarar a Israel, descobrem-se a corrupção de Efraim e as maldades de Samária; porque praticam a falsidade; o ladrão entra, e a horda dos salteadores despoja por fora.' },
      { v: 2, en: 'They don’t consider in their hearts that I remember all their wickedness. Now their own deeds have engulfed them. They are before my face.', pt: 'Não consideram no seu coração que eu me lembro de toda a sua maldade; agora, pois, os cercam as suas obras; diante da minha face estão.' },
      { v: 3, en: 'They make the king glad with their wickedness, and the princes with their lies.', pt: 'Com a sua malícia alegram ao rei, e com as suas mentiras aos príncipes.' },
      { v: 4, en: 'They are all adulterers. They are burning like an oven that the baker stops stirring, from the kneading of the dough, until it is leavened.', pt: 'Todos eles são adúlteros; são semelhantes ao forno aceso, cujo padeiro cessa de atear o fogo desde o amassar a massa até que seja levedada.' },
      { v: 5, en: 'On the day of our king, the princes made themselves sick with the heat of wine. He joined his hand with mockers.', pt: 'E no dia do nosso rei os príncipes se tornaram doentes com a excitação do vinho; o rei estendeu a sua mão com escarnecedores.' },
      { v: 6, en: 'For they have prepared their heart like an oven, while they lie in wait. Their baker sleeps all the night. In the morning it burns as a flaming fire.', pt: 'Pois têm preparado o coração como um forno, enquanto estão de espreita; toda a noite dorme a sua ira; pela manhã arde como fogo de chama.' },
      { v: 7, en: 'They are all hot as an oven, and devour their judges. All their kings have fallen. There is no one among them who calls to me.', pt: 'Eles estão todos quentes como um forno, e devoram os seus juízes; todos os seus reis caem; ninguém entre eles há que me invoque.' },
      { v: 8, en: 'Ephraim, he mixes himself among the nations. Ephraim is a pancake not turned over.', pt: 'Quanto a Efraim, ele se mistura com os povos; Efraim é um bolo que não foi virado.' },
      { v: 9, en: 'Strangers have devoured his strength, and he doesn’t realize it. Indeed, gray hairs are here and there on him, and he doesn’t realize it.', pt: 'Estrangeiros lhe devoram a força, e ele não o sabe; também as cãs se espalham sobre ele, e não o sabe.' },
      { v: 10, en: 'The pride of Israel testifies to his face; yet they haven’t returned to Yahweh their God, nor sought him, for all this.', pt: 'E a soberba de Israel testifica contra ele; todavia, não voltam para o Senhor seu Deus, nem o buscam em tudo isso.' },
      { v: 11, en: '“Ephraim is like an easily deceived dove, without understanding. They call to Egypt. They go to Assyria.', pt: 'Pois Efraim é como uma pomba, insensata, sem entendimento; invocam o Egito, vão para a Assíria.' },
      { v: 12, en: 'When they go, I will spread my net on them. I will bring them down like the birds of the sky. I will chastise them, as their congregation has heard.', pt: 'Quando forem, sobre eles estenderei a minha rede, e como aves do céu os farei descer; castigá-los-ei, conforme o que eles têm ouvido na sua congregação.' },
      { v: 13, en: 'Woe to them! For they have wandered from me. Destruction to them! For they have trespassed against me. Though I would redeem them, yet they have spoken lies against me.', pt: 'Ai deles! porque se erraram de mim; destruição sobre eles! porque se rebelaram contra mim. Quisera eu remi-los, mas falam mentiras contra mim.' },
      { v: 14, en: 'They haven’t cried to me with their heart, but they howl on their beds. They assemble themselves for grain and new wine. They turn away from me.', pt: 'Não clamam a mim de coração, mas uivam nas suas camas; para o trigo e para o mosto se ajuntam, mas contra mim se rebelam.' },
      { v: 15, en: 'Though I have taught and strengthened their arms, yet they plot evil against me.', pt: 'Contudo fui eu que os ensinei, e lhes fortaleci os braços; entretanto maquinam o mal contra mim.' },
      { v: 16, en: 'They return, but not to the Most High. They are like a faulty bow. Their princes will fall by the sword for the rage of their tongue. This will be their derision in the land of Egypt.', pt: 'Eles voltam, mas não para o Altíssimo. Fizeram-se como um arco enganador; caem à espada os seus príncipes, por causa da insolência da sua língua; este será o seu escárnio na terra do Egito.' },
    ],
    8: [
      { v: 1, en: '“Put the trumpet to your lips! Something like an eagle is over Yahweh’s house, because they have broken my covenant, and rebelled against my law.', pt: 'Põe a trombeta à tua boca. Ele vem como águia contra a casa do Senhor; porque eles transgrediram o meu pacto, e se rebelaram contra a minha lei.' },
      { v: 2, en: 'They cry to me, ‘My God, we Israel acknowledge you!’', pt: 'E a mim clamam: Deus meu, nós, Israel, te conhecemos.' },
      { v: 3, en: 'Israel has cast off that which is good. The enemy will pursue him.', pt: 'Israel desprezou o bem; o inimigo persegui-lo-á.' },
      { v: 4, en: 'They have set up kings, but not by me. They have made princes, and I didn’t approve. Of their silver and their gold they have made themselves idols, that they may be cut off.', pt: 'Eles fizeram reis, mas não por mim; constituíram príncipes, mas sem a minha aprovação; da sua prata e do seu ouro fizeram ídolos para si, para serem destruídos.' },
      { v: 5, en: 'Let Samaria throw out his calf idol! My anger burns against them! How long will it be until they are capable of purity?', pt: 'O teu bezerro, ó Samária, é rejeitado; a minha ira se acendeu contra eles; até quando serão eles incapazes da inocência?' },
      { v: 6, en: 'For this is even from Israel! The workman made it, and it is no God; indeed, the calf of Samaria shall be broken in pieces.', pt: 'Pois isso procede de Israel; um artífice o fez, e não é Deus. Será desfeito em pedaços o bezerro de Samária' },
      { v: 7, en: 'For they sow the wind, and they will reap the whirlwind. He has no standing grain. The stalk will yield no head. If it does yield, strangers will swallow it up.', pt: 'Porquanto semeiam o vento, hão de ceifar o turbilhão; não haverá seara, a erva não dará farinha; se a der, tragá-la-ão os estrangeiros.' },
      { v: 8, en: 'Israel is swallowed up. Now they are among the nations like a worthless thing.', pt: 'Israel foi devorado; agora está entre as nações como um vaso em que ninguém tem prazer.' },
      { v: 9, en: 'For they have gone up to Assyria, like a wild donkey wandering alone. Ephraim has hired lovers for himself.', pt: 'Porque subiram à Assíria, qual asno selvagem andando sozinho; mercou Efraim amores.' },
      { v: 10, en: 'But although they sold themselves among the nations, I will now gather them; and they begin to waste away because of the oppression of the king of mighty ones.', pt: 'Todavia, ainda que eles merquem entre as nações, eu as congregarei; já começaram a ser diminuídos por causa da carga do rei dos príncipes.' },
      { v: 11, en: 'Because Ephraim has multiplied altars for sinning, they became for him altars for sinning.', pt: 'Ainda que Efraim tem multiplicado altares, estes se lhe tornaram altares para pecar.' },
      { v: 12, en: 'I wrote for him the many things of my law; but they were regarded as a strange thing.', pt: 'Escrevi para ele miríades de coisas da minha lei; mas isso é para ele como coisa estranha.' },
      { v: 13, en: 'As for the sacrifices of my offerings, they sacrifice meat and eat it; But Yahweh doesn’t accept them. Now he will remember their iniquity, and punish their sins. They will return to Egypt.', pt: 'Quanto aos sacrifícios das minhas ofertas, eles sacrificam carne, e a comem; mas o Senhor não os aceita; agora se lembrará da iniqüidade deles, e punirá os seus pecados; eles voltarão para o Egito.' },
      { v: 14, en: 'For Israel has forgotten his Maker and built palaces; and Judah has multiplied fortified cities; but I will send a fire on his cities, and it will devour its fortresses.”', pt: 'Pois Israel se esqueceu do seu Criador, e edificou palácios, e Judá multiplicou cidades fortificadas. Mas eu enviarei sobre as suas cidades um fogo que consumirá os seus castelos.' },
    ],
    9: [
      { v: 1, en: 'Don’t rejoice, Israel, to jubilation like the nations; for you were unfaithful to your God. You love the wages of a prostitute at every grain threshing floor.', pt: 'Não te alegres, ó Israel, não exultes como os povos; pois te prostituíste, apartando-te do teu Deus; amaste a paga de meretriz sobre todas as eiras de trigo.' },
      { v: 2, en: 'The threshing floor and the wine press won’t feed them, and the new wine will fail her.', pt: 'A eira e o lagar não os manterão, e o vinho novo lhes faltará.' },
      { v: 3, en: 'They won’t dwell in Yahweh’s land; but Ephraim will return to Egypt, and they will eat unclean food in Assyria.', pt: 'Na terra do Senhor não permanecerão; mas Efraim tornará ao Egito, e na Assíria comerão comida imunda.' },
      { v: 4, en: 'They won’t pour out wine offerings to Yahweh, neither will they be pleasing to him. Their sacrifices will be to them like the bread of mourners; all who eat of it will be polluted; for their bread will be for their appetite. It will not come into Yahweh’s house.', pt: 'Não derramarão libações de vinho ao Senhor, nem lhe agradarão com as suas ofertas. O pão deles será como pão de pranteadores; todos os que dele comerem serão imundos; pois o seu pão será somente para o seu apetite; não entrará na casa do Senhor.' },
      { v: 5, en: 'What will you do in the day of solemn assembly, and in the day of the feast of Yahweh?', pt: 'Que fareis vós no dia da solenidade, e no dia da festa do Senhor?' },
      { v: 6, en: 'For, behold, they have gone away from destruction. Egypt will gather them up. Memphis will bury them. Nettles will possess their pleasant things of silver. Thorns will be in their tents.', pt: 'Porque, eis que eles se foram por causa da destruição, mas o Egito os recolherá, Mênfis os sepultará; as suas coisas preciosas de prata as urtigas as possuirão; espinhos crescerão nas suas tendas.' },
      { v: 7, en: 'The days of visitation have come. The days of reckoning have come. Israel will consider the prophet to be a fool, and the man who is inspired to be insane, because of the abundance of your sins, and because your hostility is great.', pt: 'Chegaram os dias da punição, chegaram os dias da retribuição; Israel o saberá; o profeta é um insensato, o homem possesso de espírito é um louco; por causa da abundância da tua iniqüidade e do teu grande ódio.' },
      { v: 8, en: 'A prophet watches over Ephraim with my God. A fowler’s snare is on all of his paths, and hostility in the house of his God.', pt: 'O profeta é a sentinela de Efraim, o povo do meu Deus; contudo um laço de caçador de aves se acha em todos os seus caminhos, e inimizade na casa do seu Deus.' },
      { v: 9, en: 'They have deeply corrupted themselves, as in the days of Gibeah. He will remember their iniquity. He will punish them for their sins.', pt: 'Muito profundamente se corromperam, como nos dias de Gibeá; ele se lembrará das iniqüidades deles, e punirá os seus pecados.' },
      { v: 10, en: 'I found Israel like grapes in the wilderness. I saw your fathers as the first ripe in the fig tree at its first season; but they came to Baal Peor, and consecrated themselves to the shameful thing, and became abominable like that which they loved.', pt: 'Achei a Israel como uvas no deserto, vi a vossos pais como a fruta temporã da figueira no seu princípio; mas eles foram para Baal- Peor, e se consagraram a essa coisa vergonhosa, e se tornaram abomináveis como aquilo que amaram.' },
      { v: 11, en: 'As for Ephraim, their glory will fly away like a bird. There will be no birth, no one with child, and no conception.', pt: 'Quanto a Efraim, a sua glória como ave voará; não haverá nascimento, nem gravidez, nem concepção.' },
      { v: 12, en: 'Though they bring up their children, yet I will bereave them, so that not a man shall be left. Indeed, woe also to them when I depart from them!', pt: 'Ainda que venham criar seus filhos, eu os privarei deles, para que não fique nenhum homem. Ai deles, quando deles eu me apartar!' },
      { v: 13, en: 'I have seen Ephraim, like Tyre, planted in a pleasant place; but Ephraim will bring out his children to the murderer.', pt: 'Efraim, assim como vi a Tiro, está plantado num lugar aprazível; mas Efraim levará seus filhos ao matador.' },
      { v: 14, en: 'Give them—Yahweh what will you give? Give them a miscarrying womb and dry breasts.', pt: 'Dá-lhes, ó Senhor; mas que lhes darás? dá-lhes uma madre que aborte e seios ressecados.' },
      { v: 15, en: '“All their wickedness is in Gilgal; for there I hated them. Because of the wickedness of their deeds I will drive them out of my house! I will love them no more. All their princes are rebels.', pt: 'Toda a sua malícia se acha em Gilgal; pois ali é que lhes concebi ódio; por causa da maldade das suas obras lançá-los-ei fora de minha casa. Não os amarei mais; todos os seus príncipes são rebeldes.' },
      { v: 16, en: 'Ephraim is struck. Their root has dried up. They will bear no fruit. Even though they give birth, yet I will kill the beloved ones of their womb.”', pt: 'Efraim foi ferido, secou-se a sua raiz; eles não darão fruto; sim, ainda que gerem, eu matarei os frutos desejáveis do seu ventre.' },
      { v: 17, en: 'My God will cast them away, because they did not listen to him; and they will be wanderers among the nations.', pt: 'O meu Deus os rejeitará, porque não o ouviram; e errantes andarão entre as nações.' },
    ],
    10: [
      { v: 1, en: 'Israel is a luxuriant vine that produces his fruit. According to the abundance of his fruit he has multiplied his altars. As their land has prospered, they have adorned their sacred stones.', pt: 'Israel é vide frondosa que dá o seu fruto; conforme a abundância do seu fruto, assim multiplicou os altares; conforme a prosperidade da terra, assim fizeram belas colunas.' },
      { v: 2, en: 'Their heart is divided. Now they will be found guilty. He will demolish their altars. He will destroy their sacred stones.', pt: 'O seu coração está dividido, por isso serão culpados; ele derribará os altares deles, e lhes destruirá as colunas.' },
      { v: 3, en: 'Surely now they will say, “We have no king; for we don’t fear Yahweh; and the king, what can he do for us?”', pt: 'Certamente agora dirão: Não temos rei, porque não tememos ao Senhor; e o rei, que pode ele fazer por nós?' },
      { v: 4, en: 'They make promises, swearing falsely in making covenants. Therefore judgment springs up like poisonous weeds in the furrows of the field.', pt: 'Falam palavras vãs; juram falsamente, fazendo pactos; por isso brota o juízo como erva peçonhenta nos sulcos dos campos.' },
      { v: 5, en: 'The inhabitants of Samaria will be in terror for the calves of Beth Aven; for its people will mourn over it, Along with its priests who rejoiced over it, for its glory, because it has departed from it.', pt: 'Os moradores de Samária serão atemorizados por causa do bezerro de Bete-Áven. O seu povo se lamentará por causa dele, como também prantearão os seus sacerdotes idólatras por causa da sua glória, que se apartou dela.' },
      { v: 6, en: 'It also will be carried to Assyria for a present to a great king. Ephraim will receive shame, and Israel will be ashamed of his own counsel.', pt: 'Também será ele levado para Assíria como um presente ao rei Jarebe; Efraim ficará confuso, e Israel se envergonhará por causa do seu próprio conselho.' },
      { v: 7, en: 'Samaria and her king float away, like a twig on the water.', pt: 'O rei de Samária será desfeito como a espuma sobre a face da água.' },
      { v: 8, en: 'The high places also of Aven, the sin of Israel, will be destroyed. The thorn and the thistle will come up on their altars. They will tell the mountains, “Cover us!” and the hills, “Fall on us!”', pt: 'E os altos de Áven, pecado de Israel, serão destruídos; espinhos e cardos crescerão sobre os seus altares; e dirão aos montes: Cobri-nos! e aos outeiros: Caí sobre nós!' },
      { v: 9, en: '“Israel, you have sinned from the days of Gibeah. There they remained. The battle against the children of iniquity doesn’t overtake them in Gibeah.', pt: 'Desde os dias de Gibeá tens pecado, ó Israel; ali permaneceram; a peleja contra os filhos da iniqüidade não os alcançará em Gibeá.' },
      { v: 10, en: 'When it is my desire, I will chastise them; and the nations will be gathered against them, when they are bound to their two transgressions.', pt: 'Quando eu quiser, castigá-los-ei; e os povos se congregarão contra eles, quando forem castigados pela sua dupla transgressao.' },
      { v: 11, en: 'Ephraim is a trained heifer that loves to thresh; so I will put a yoke on her beautiful neck. I will set a rider on Ephraim. Judah will plow. Jacob will break his clods.', pt: 'Porque Efraim era uma novilha domada, que gostava de trilhar; e eu poupava a formosura do seu pescoço; mas porei arreios sobre Efraim; Judá lavrará; Jacó desfará os torrões.' },
      { v: 12, en: 'Sow to yourselves in righteousness, reap according to kindness. Break up your fallow ground; for it is time to seek Yahweh, until he comes and rains righteousness on you.', pt: 'Semeai para vós em justiça, colhei segundo a misericórdia; lavrai o campo alqueivado; porque é tempo de buscar ao Senhor, até que venha e chova a justiça sobre vós.' },
      { v: 13, en: 'You have plowed wickedness. You have reaped iniquity. You have eaten the fruit of lies, for you trusted in your way, in the multitude of your mighty men.', pt: 'Lavrastes a impiedade, segastes a iniqüidade, e comestes o fruto da mentira; porque confiaste no teu caminho, na multidão dos teus valentes.' },
      { v: 14, en: 'Therefore a battle roar will arise among your people, and all your fortresses will be destroyed, as Shalman destroyed Beth Arbel in the day of battle. The mother was dashed in pieces with her children.', pt: 'Portanto, entre o teu povo se levantará tumulto de guerra, e todas as tuas fortalezas serão destruídas, como Salmã destruiu a Bete-Arbel no dia da batalha; a mãe ali foi despedaçada juntamente com os filhos.' },
      { v: 15, en: 'So Bethel will do to you because of your great wickedness. At daybreak the king of Israel will be destroyed.', pt: 'Assim vos fará Betel, por causa da vossa grande malícia; de madrugada será o rei de Israel totalmente destruído.' },
    ],
    11: [
      { v: 1, en: '“When Israel was a child, then I loved him, and called my son out of Egypt.', pt: 'Quando Israel era menino, eu o amei, e do Egito chamei a meu filho.' },
      { v: 2, en: 'They called to them, so they went from them. They sacrificed to the Baals, and burned incense to engraved images.', pt: 'Quanto mais eu os chamava, tanto mais se afastavam de mim; sacrificavam aos baalins, e queimavam incenso às imagens esculpidas.' },
      { v: 3, en: 'Yet I taught Ephraim to walk. I took them by his arms; but they didn’t know that I healed them.', pt: 'Todavia, eu ensinei aos de Efraim a andar; tomei-os nos meus braços; mas não entendiam que eu os curava.' },
      { v: 4, en: 'I drew them with cords of a man, with ties of love; and I was to them like those who lift up the yoke on their necks; and I bent down to him and I fed him.', pt: 'Atraí-os com cordas humanas, com laços de amor; e fui para eles como os que tiram o jugo de sobre as suas queixadas, e me inclinei para lhes dar de comer.' },
      { v: 5, en: '“They won’t return into the land of Egypt; but the Assyrian will be their king, because they refused to repent.', pt: 'Não voltarão para a terra do Egito; mas a Assíria será seu rei; porque recusam converter-se.' },
      { v: 6, en: 'The sword will fall on their cities, and will destroy the bars of their gates, and will put an end to their plans.', pt: 'Cairá a espada sobre as suas cidades, e consumirá os seus ferrolhos; e os devorará nas suas fortalezas.' },
      { v: 7, en: 'My people are determined to turn from me. Though they call to the Most High, he certainly won’t exalt them.', pt: 'Porque o meu povo é inclinado a desviar-se de mim; ainda que clamem ao Altíssimo, nenhum deles o exalta.' },
      { v: 8, en: '“How can I give you up, Ephraim? How can I hand you over, Israel? How can I make you like Admah? How can I make you like Zeboiim? My heart is turned within me, my compassion is aroused.', pt: 'Como te deixaria, ó Efraim? como te entregaria, ó Israel? como te faria como Admá? ou como Zeboim? Está comovido em mim o meu coração, as minhas compaixões à uma se acendem.' },
      { v: 9, en: 'I will not execute the fierceness of my anger. I will not return to destroy Ephraim: for I am God, and not man; the Holy One among you; and I will not come in wrath.', pt: 'Não executarei o furor da minha ira; não voltarei para destruir a Efraim, porque eu sou Deus e não homem, o Santo no meio de ti; eu não virei com ira.' },
      { v: 10, en: 'They will walk after Yahweh, who will roar like a lion; for he will roar, and the children will come trembling from the west.', pt: 'Andarão após o Senhor; ele bramará como leão; e, bramando ele, os filhos, tremendo, virão do ocidente.' },
      { v: 11, en: 'They will come trembling like a bird out of Egypt, and like a dove out of the land of Assyria; and I will settle them in their houses,” says Yahweh.', pt: 'Também, tremendo, virão como um passarinho os do Egito, e como uma pomba os da terra da Assíria; e os farei habitar em suas casas, diz o Senhor.' },
      { v: 12, en: 'Ephraim surrounds me with falsehood, and the house of Israel with deceit. Judah still strays from God, and is unfaithful to the Holy One.', pt: 'Efraim me cercou com mentira, e a casa de Israel com engano; mas Judá ainda domina com Deus, e com o Santo está fiel.' },
    ],
    12: [
      { v: 1, en: 'Ephraim feeds on wind, and chases the east wind. He continually multiplies lies and desolation. They make a covenant with Assyria, and oil is carried into Egypt.', pt: 'Efraim apascenta o vento, segue o vento oriental todo o dia; multiplica a mentira e a destruição; e fazem aliança com a Assíria, e o azeite se leva ao Egito' },
      { v: 2, en: 'Yahweh also has a controversy with Judah, and will punish Jacob according to his ways; according to his deeds he will repay him.', pt: 'O Senhor também com Judá tem contenda, e castigará a Jacó segundo os seus caminhos; segundo as suas obras o recompensará.' },
      { v: 3, en: 'In the womb he took his brother by the heel; and in his manhood he contended with God.', pt: 'No ventre pegou do calcanhar de seu irmão; e na sua idade varonil lutou com Deus.' },
      { v: 4, en: 'Indeed, he struggled with the angel, and prevailed; he wept, and made supplication to him. He found him at Bethel, and there he spoke with us,', pt: 'Lutou com o anjo, e prevaleceu; chorou, e lhe fez súplicas. Em Betel o achou, e ali falou Deus com ele;' },
      { v: 5, en: 'even Yahweh, the God of Armies; Yahweh is his name of renown!', pt: 'sim, o Senhor, o Deus dos exércitos; o Senhor e o seu nome.' },
      { v: 6, en: 'Therefore turn to your God. Keep kindness and justice, and wait continually for your God.', pt: 'Tu, pois, converte-te a teu Deus; guarda a benevolência e a justiça, e em teu Deus espera sempre.' },
      { v: 7, en: 'A merchant has dishonest scales in his hand. He loves to defraud.', pt: 'Quanto a Canaã, tem nas mãos balança enganadora; ama a opressão.' },
      { v: 8, en: 'Ephraim said, “Surely I have become rich, I have found myself wealth. In all my wealth they won’t find in me any iniquity that is sin.”', pt: 'Diz Efraim: Certamente eu me tenho enriquecido, tenho adquirido para mim grandes bens; em todo o meu trabalho não acharão em mim iniqüidade alguma que seja pecado.' },
      { v: 9, en: '“But I am Yahweh your God from the land of Egypt. I will yet again make you dwell in tents, as in the days of the solemn feast.', pt: 'Mas eu sou o Senhor teu Deus, desde a terra do Egito; eu ainda te farei habitar de novo em tendas, como nos dias da festa solene.' },
      { v: 10, en: 'I have also spoken to the prophets, and I have multiplied visions; and by the ministry of the prophets I have used parables.', pt: 'Também falei aos profetas, e multipliquei as visões; e pelo ministério dos profetas usei de parábolas.' },
      { v: 11, en: 'If Gilead is wicked, surely they are worthless. In Gilgal they sacrifice bulls. Indeed, their altars are like heaps in the furrows of the field.', pt: 'Não é Gileade iniqüidade? pura vaidade são eles. Em Gilgal sacrificam bois; os seus altares são como montões de pedras nos sulcos dos campos.' },
      { v: 12, en: 'Jacob fled into the country of Aram, and Israel served to get a wife, and for a wife he tended flocks and herds.', pt: 'Jacó fugiu para o campo de Arã, e Israel serviu por uma mulher, sim, por uma mulher guardou o gado.' },
      { v: 13, en: 'By a prophet Yahweh brought Israel up out of Egypt, and by a prophet he was preserved.', pt: 'Mas o Senhor por meio dum profeta fez subir a Israel do Egito, e por um profeta foi ele preservado.' },
      { v: 14, en: 'Ephraim has bitterly provoked anger. Therefore his blood will be left on him, and his Lord will repay his contempt.', pt: 'Efraim mui amargamente provocou-lhe a ira; portanto sobre ele será deixado o seu sangue, e o seu Senhor fará cair sobre ele o seu opróbrio.' },
    ],
    13: [
      { v: 1, en: 'When Ephraim spoke, there was trembling. He exalted himself in Israel, but when he became guilty in Baal, he died.', pt: 'Quando Efraim falava, tremia-se; foi exaltado em Israel; mas quando ele se fez culpado no tocante a Baal, morreu.' },
      { v: 2, en: 'Now they sin more and more, and have made themselves molten images of their silver, even idols according to their own understanding, all of them the work of the craftsmen. They say of them, ‘They offer human sacrifice and kiss the calves.’', pt: 'E agora pecam mais e mais, e da sua prata fazem imagens fundidas, ídolos segundo o seu entendimento, todos eles obra de artífices, e dizem: Oferecei sacrifícios a estes. Homens beijam aos bezerros!' },
      { v: 3, en: 'Therefore they will be like the morning mist, and like the dew that passes away early, like the chaff that is driven with the whirlwind out of the threshing floor, and like the smoke out of the chimney.', pt: 'Por isso serão como a nuvem de manhã, e como o orvalho que cedo passa; como a palha que se lança fora da eira, e como a fumaça que sai pela janela.' },
      { v: 4, en: '“Yet I am Yahweh your God from the land of Egypt; and you shall acknowledge no god but me, and besides me there is no savior.', pt: 'Todavia, eu sou o Senhor teu Deus desde a terra do Egito; portanto não conhecerás outro deus além de mim, porque não há salvador senão eu.' },
      { v: 5, en: 'I knew you in the wilderness, in the land of great drought.', pt: 'Eu te conheci no deserto, em terra muito seca.' },
      { v: 6, en: 'According to their pasture, so were they filled; they were filled, and their heart was exalted. Therefore they have forgotten me.', pt: 'Depois eles se fartaram em proporção do seu pasto; e estando fartos, ensoberbeceu-se-lhes o coração, por isso esqueceram de mim.' },
      { v: 7, en: 'Therefore I am like a lion to them. Like a leopard, I will lurk by the path.', pt: 'Portanto serei para eles como leão; como leopardo espreitarei junto ao caminho;' },
      { v: 8, en: 'I will meet them like a bear that is bereaved of her cubs, and will tear the covering of their heart. There I will devour them like a lioness. The wild animal will tear them.', pt: 'Como ursa roubada dos seus cachorros lhes sairei ao encontro, e lhes romperei as teias do coração; e ali os devorarei como leoa; as feras do campo os despedaçarão.' },
      { v: 9, en: 'You are destroyed, Israel, because you are against me, against your help.', pt: 'Destruir-te-ei, ó Israel; quem te pode socorrer?' },
      { v: 10, en: 'Where is your king now, that he may save you in all your cities? And your judges, of whom you said, ‘Give me a king and princes?’', pt: 'Onde está agora o teu rei, para que te salve em todas as tuas cidades? e os teus juízes, dos quais disseste: Dá-me rei e príncipes?' },
      { v: 11, en: 'I have given you a king in my anger, and have taken him away in my wrath.', pt: 'Dei-te um rei na minha ira, e tirei-o no meu furor.' },
      { v: 12, en: 'The guilt of Ephraim is stored up. His sin is stored up.', pt: 'A iniqüidade de Efraim está atada, o seu pecado está armazenado.' },
      { v: 13, en: 'The sorrows of a travailing woman will come on him. He is an unwise son; for when it is time, he doesn’t come to the opening of the womb.', pt: 'Dores de mulher de parto lhe sobrevirão; ele é filho insensato; porque é tempo e não está no lugar em que deve vir à luz.' },
      { v: 14, en: 'I will ransom them from the power of Sheol. I will redeem them from death! Death, where are your plagues? Sheol, where is your destruction? “Compassion will be hidden from my eyes.', pt: 'Eu os remirei do poder do Seol, e os resgatarei da morte. Onde estão, ó morte, as tuas pragas? Onde está, ó Seol, a tua destruição? A compaixão está escondida de meus olhos.' },
      { v: 15, en: 'Though he is fruitful among his brothers, an east wind will come, the breath of Yahweh coming up from the wilderness; and his spring will become dry, and his fountain will be dried up. He will plunder the storehouse of treasure.', pt: 'Ainda que ele dê fruto entre os seus irmãos, virá o vento oriental, vento do Senhor, subindo do deserto, e secar-se-á a sua nascente, e se estancará a sua fonte; ele saqueará o tesouro de todos os vasos desejáveis.' },
      { v: 16, en: 'Samaria will bear her guilt; for she has rebelled against her God. They will fall by the sword. Their infants will be dashed in pieces, and their pregnant women will be ripped open.”', pt: 'Samária levará sobre si a sua culpa, porque se rebelou contra o seu Deus; cairá à espada; seus filhinhos serão despedaçados, e as suas mulheres grávidas serão fendidas.' },
    ],
    14: [
      { v: 1, en: 'Israel, return to Yahweh your God; for you have fallen because of your sin.', pt: 'Volta, ó Israel, para o Senhor teu Deus; porque pela tua iniqüidade tens caído.' },
      { v: 2, en: 'Take words with you, and return to Yahweh. Tell him, “Forgive all our sins, and accept that which is good: so we offer our lips like bulls.', pt: 'Tomai convosco palavras, e voltai para o Senhor; dizei-lhe: Tira toda a iniqüidade, e aceita o que é bom; e ofereceremos como novilhos os sacrifícios dos nossos lábios.' },
      { v: 3, en: 'Assyria can’t save us. We won’t ride on horses; neither will we say any more to the work of our hands, ‘Our gods!’ for in you the fatherless finds mercy.”', pt: 'Não nos salvará a Assíria, não iremos montados em cavalos; e à obra das nossas mãos já não diremos: Tu és o nosso Deus; porque em ti o órfão acha a misericórdia.' },
      { v: 4, en: '“I will heal their waywardness. I will love them freely; for my anger is turned away from him.', pt: 'Eu sararei a sua apostasia, eu voluntariamente os amarei; porque a minha ira se apartou deles.' },
      { v: 5, en: 'I will be like the dew to Israel. He will blossom like the lily, and send down his roots like Lebanon.', pt: 'Eu serei para Israel como o orvalho; ele florescerá como o lírio, e lançará as suas raízes como o Líbano.' },
      { v: 6, en: 'His branches will spread, and his beauty will be like the olive tree, and his fragrance like Lebanon.', pt: 'Estender-se-ão as suas vergônteas, e a sua formosura será como a da oliveira, a sua fragrância como a do Líbano.' },
      { v: 7, en: 'Men will dwell in his shade. They will revive like the grain, and blossom like the vine. Their fragrance will be like the wine of Lebanon.', pt: 'Voltarão os que habitam à sua sombra; reverdecerão como o trigo, e florescerão como a vide; o seu renome será como o do vinho do Líbano.' },
      { v: 8, en: 'Ephraim, what have I to do any more with idols? I answer, and will take care of him. I am like a green cypress tree; from me your fruit is found.”', pt: 'ç Efraim, que tenho eu com os ídolos? Sou eu que respondo, e cuido de ti. Eu sou como a faia verde; de mim é achado o teu fruto.' },
      { v: 9, en: 'Who is wise, that he may understand these things? Who is prudent, that he may know them? For the ways of Yahweh are right, and the righteous walk in them; But the rebellious stumble in them.', pt: 'Quem é sábio, para que entenda estas coisas? prudente, para que as saiba? porque os caminhos do Senhor são retos, e os justos andarão neles; mas os transgressores neles cairão.' },
    ],
  },
};

export default book;
